import{_ as o}from"./_plugin-vue_export-helper.cdc0426e.js";import{o as p,c,a as n,b as s,d as e,e as t,r as l}from"./app.6aef24fd.js";const i={},u=t(`<h2 id="let-const" tabindex="-1"><a class="header-anchor" href="#let-const" aria-hidden="true">#</a> let/const</h2><p><code>let/const</code> 是 <code>ES6</code> 中提出的新的用于定义变量的方式，与 <code>var</code> 相比具有以下特性</p><h3 id="全局作用域下声明的变量不会成为-window-对象的属性-方法" tabindex="-1"><a class="header-anchor" href="#全局作用域下声明的变量不会成为-window-对象的属性-方法" aria-hidden="true">#</a> 全局作用域下声明的变量不会成为 window 对象的属性/方法</h3><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 全局作用域下 var 声明的变量会自动成为 window 对象的属性/方法</span>
<span class="token keyword">var</span> my_github <span class="token operator">=</span> <span class="token string">&#39;github.com/yuanyxh&#39;</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>window<span class="token punctuation">.</span>my_github<span class="token punctuation">)</span><span class="token punctuation">;</span>      <span class="token comment">// github.com/yuanyxh</span>

<span class="token comment">// 全局作用域下 let/const 声明的变量不会成为 window 对象的属性/方法</span>
<span class="token keyword">let</span> my_name <span class="token operator">=</span> <span class="token string">&#39;yuanyxh&#39;</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>window<span class="token punctuation">.</span>my_name<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// undefined</span>

<span class="token keyword">const</span> <span class="token constant">MY_BLOG</span> <span class="token operator">=</span> <span class="token string">&#39;yuanyxh.com&#39;</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>window<span class="token punctuation">.</span><span class="token constant">MY_BLOG</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// undefined</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="块作用域" tabindex="-1"><a class="header-anchor" href="#块作用域" aria-hidden="true">#</a> 块作用域</h3><p><code>let/const</code> 具有块作用域，即变量作用域被限制在当前代码块，这为什么是重要的，我们看一个经典示例</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// var</span>
<span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">var</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> <span class="token number">5</span><span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token function">setTimeout</span><span class="token punctuation">(</span><span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>i<span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">// 5 5 5 5 5</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token comment">// let</span>
<span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">let</span> j <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> j <span class="token operator">&lt;</span> <span class="token number">5</span><span class="token punctuation">;</span> j<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token function">setTimeout</span><span class="token punctuation">(</span><span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>j<span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">// 0 1 2 3 4</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>可以看到，使用 <code>let</code> 定义的变量输出似乎符合预期效果，使用 <code>var</code> 定义的变量则出了问题，为什么？</p><p><code>JS</code> 引擎在内部会为每次循环迭代声明新的迭代变量，每个循环引用的都是不同的变量实例， 但因为 <code>var</code> 定义的变量没有块作用域，变量渗透到了循环体外，每个 <code>setTimeout</code> 引用的都是同一个循环体外的变量 <code>i</code>，<code>i</code> 最后一次的值是 5，不满足循环要求退出了循环，所以此时循环体外的 <code>i</code> 值为 5，执行顺序大致如下</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 第一次循环 循环体内外 i 值为 0</span>
<span class="token comment">// 添加一个异步任务</span>

<span class="token comment">// 第二次循环 循环体内外 i 值为 1</span>
<span class="token comment">// 添加一个异步任务</span>

<span class="token comment">// 第三次循环 循环体内外 i 值为 2</span>
<span class="token comment">// 添加一个异步任务</span>

<span class="token comment">// 第四次循环 循环体内外 i 值为 3</span>
<span class="token comment">// 添加一个异步任务</span>

<span class="token comment">// 第五次循环 循环体内外 i 值为 4</span>
<span class="token comment">// 添加一个异步任务</span>

<span class="token comment">// 循环结束 循环体内外 i 值为 5</span>

<span class="token comment">// 消耗异步任务队列 输出 i</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>为考虑浏览器兼容性，很多编译转换工具都会将 <code>let/const</code> 声明编译为 <code>var</code> 声明，那怎么解决上述问题呢，如下</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// IIFE and closure</span>
<span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">var</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> <span class="token number">5</span><span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token punctuation">(</span><span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token parameter">j</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token function">setTimeout</span><span class="token punctuation">(</span><span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>j<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">(</span>i<span class="token punctuation">)</span>
<span class="token punctuation">}</span>

<span class="token comment">// or</span>
<span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">var</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> <span class="token number">5</span><span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">try</span> <span class="token punctuation">{</span>
    <span class="token keyword">throw</span> i<span class="token punctuation">;</span>
  <span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span>num<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token function">setTimeout</span><span class="token punctuation">(</span><span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>num<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>第一处代码利用了函数 <code>立即调用表达式(IIFE)</code>，将迭代变量传递给了 <code>IIFE</code> 的形参 <code>j</code>，<code>var</code> 是有函数作用域的，所以每个 <code>setTimeout</code> 引用的都是不同的变量实例。</p><p>第二处代码利用了 <code>try ... catch</code> 中的 <code>catch</code> 块具有块作用域的特点实现了相同效果。</p><h3 id="暂时性死区" tabindex="-1"><a class="header-anchor" href="#暂时性死区" aria-hidden="true">#</a> 暂时性死区</h3><p><code>var</code> 有声明提升<sup class="footnote-ref"><a href="#footnote1">[1]</a><a class="footnote-anchor" id="footnote-ref1"></a></sup>，而 <code>let/const</code> 声明的变量不允许在词法声明前使用，即 <code>暂时性死区</code><sup class="footnote-ref"><a href="#footnote2">[2]</a><a class="footnote-anchor" id="footnote-ref2"></a></sup>，如下</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// var</span>
<span class="token comment">// 允许，但强烈不建议</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>j<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// undefined</span>
<span class="token keyword">var</span> j <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>

<span class="token comment">// let</span>
<span class="token comment">// 不允许</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>i<span class="token punctuation">)</span> <span class="token comment">// ReferenceError</span>
<span class="token keyword">let</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>可以看到 <code>j</code> 的声明被提升到了顶部，但赋值操作未被提升，所以打印结果为 <code>undefined</code>，相当于</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> j<span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>j<span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">// undefined</span>
j <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>let/const</code> 声明的变量本质上也存在声明提升，但 <code>JS</code> 引擎对其进行了词法检查，不允许 <code>let/const</code> 定义的变量在词法声明前使用。</p><h3 id="同一作用域不允许重复声明" tabindex="-1"><a class="header-anchor" href="#同一作用域不允许重复声明" aria-hidden="true">#</a> 同一作用域不允许重复声明</h3><p><code>let/const</code> 声明的变量在同一作用域内不允许重复声明</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// var</span>
<span class="token comment">// 允许，但不推荐</span>
<span class="token keyword">var</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>
<span class="token keyword">var</span> i <span class="token operator">=</span> <span class="token number">10</span><span class="token punctuation">;</span>

<span class="token comment">// let</span>
<span class="token comment">// 不允许</span>
<span class="token keyword">let</span> j <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>
<span class="token keyword">let</span> j <span class="token operator">=</span> <span class="token number">10</span><span class="token punctuation">;</span>  <span class="token comment">// SyntaxError</span>

<span class="token comment">// compose</span>
<span class="token comment">// 不允许</span>
<span class="token keyword">var</span> k <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>
<span class="token keyword">let</span> k <span class="token operator">=</span> <span class="token number">10</span><span class="token punctuation">;</span>  <span class="token comment">// SyntaxError</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>另外，<code>var</code> 声明的变量，在同一作用域内重复声明且后续声明未赋值时，后面的变量声明会使用前面变量声明的值</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// var</span>
<span class="token keyword">var</span> i <span class="token operator">=</span> <span class="token number">10</span><span class="token punctuation">;</span>
<span class="token keyword">var</span> i<span class="token punctuation">;</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>i<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 10</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="let-与-const-的区别" tabindex="-1"><a class="header-anchor" href="#let-与-const-的区别" aria-hidden="true">#</a> let 与 const 的区别</h3><ul><li><code>let</code> 定义的变量，变量值允许改变</li><li><code>const</code> 定义的变量，变量值不允许改变，且声明变量的同时必须进行初始化</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// let</span>
<span class="token keyword">let</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>
i <span class="token operator">=</span> <span class="token number">10</span><span class="token punctuation">;</span>

<span class="token comment">// const</span>
<span class="token keyword">const</span> <span class="token constant">TEST</span> <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>
<span class="token constant">TEST</span> <span class="token operator">=</span> <span class="token number">10</span><span class="token punctuation">;</span>  <span class="token comment">// TypeError</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>const</code> 定义的变量不能改变的是变量对数据的引用，但数据本身是可以改变的</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// const</span>
<span class="token keyword">const</span> obj <span class="token operator">=</span> <span class="token punctuation">{</span> <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;yuanyxh&#39;</span><span class="token punctuation">,</span> <span class="token literal-property property">blog</span><span class="token operator">:</span> <span class="token string">&#39;yuanyxh.com&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">;</span>
obj<span class="token punctuation">.</span>name <span class="token operator">=</span> <span class="token string">&#39;jack&#39;</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>obj<span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">// { name: &#39;jack&#39;, blog: &#39;yuanyxh.com&#39; }</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="最佳实践" tabindex="-1"><a class="header-anchor" href="#最佳实践" aria-hidden="true">#</a> 最佳实践</h3><p>以下给出三种变量声明方式的最佳实践，摘自阅读的书籍与个人理解</p><ul><li>优先使用 <code>let/const</code></li><li>对于始终不变的数据优先使用 <code>const</code></li><li>对于尚未确定是否会改变的数据优先使用 <code>const</code>，以后改变数据时代码编辑工具会报语法错误</li><li>预先声明所有将要使用的变量</li></ul><h2 id="参考资料" tabindex="-1"><a class="header-anchor" href="#参考资料" aria-hidden="true">#</a> 参考资料</h2>`,34),d=n("br",null,null,-1),r=n("br",null,null,-1),k={href:"https://www.ecma-international.org/publications-and-standards/standards/ecma-262/",target:"_blank",rel:"noopener noreferrer"},v=n("br",null,null,-1),m={href:"https://kangax.github.io/compat-table/es6/",target:"_blank",rel:"noopener noreferrer"},b=n("br",null,null,-1),h={href:"https://ecma262.docschina.org/#sec-overview",target:"_blank",rel:"noopener noreferrer"},f=t('<hr class="footnotes-sep"><section class="footnotes"><ol class="footnotes-list"><li id="footnote1" class="footnote-item"><p>声明提升：指在进入新的执行上下文时，JavaScript 引擎会先将当前执行上下文中的所有 <code>变量/函数</code> 声明提升到顶部并预先分配内存。变量只提升声明，不提升赋值；函数声明会被整体提升。 <a href="#footnote-ref1" class="footnote-backref">↩︎</a></p></li><li id="footnote2" class="footnote-item"><p>暂时性死区：指当前作用域开始到 <code>let/const</code> 变量词法声明之间的区域 <a href="#footnote-ref2" class="footnote-backref">↩︎</a></p></li></ol></section>',2);function g(y,w){const a=l("ExternalLinkIcon");return p(),c("div",null,[u,n("blockquote",null,[n("p",null,[s("《JavaScript 高级程序设计》"),d,s(" 《你不知道的 JavaScript》"),r,n("a",k,[s("ECMAScript 规范"),e(a)]),v,n("a",m,[s("ECMAScript 特性兼容表"),e(a)]),b,n("a",h,[s("ECMAScript 规范部分译文"),e(a)])])]),f])}const x=o(i,[["render",g],["__file","ES6-新特性详解 - let与const.html.vue"]]);export{x as default};
